import{_ as a,o as e,c as n,a0 as o}from"./chunks/framework.DV6pVIgV.js";const c=JSON.parse('{"title":"雲端入門","description":"","frontmatter":{},"headers":[],"relativePath":"clf-c02/1.md","filePath":"clf-c02/1.md","lastUpdated":1783683776000}'),r={name:"clf-c02/1.md"};function i(s,t,d,l,g,p){return e(),n("div",null,[...t[0]||(t[0]=[o(`<h1 id="雲端入門" tabindex="-1">雲端入門 <a class="header-anchor" href="#雲端入門" aria-label="Permalink to &quot;雲端入門&quot;">​</a></h1><p>Amazon Web Services（AWS）是全球最大的雲端平台，提供運算、儲存、資料庫、網路等數百種「隨開即用」的服務。 這章是雲端的定義、服務分層方式、實體基礎設施、安全責任的劃分，後面每個章節都會用到這些基礎。</p><h2 id="什麼是雲端運算" tabindex="-1">什麼是雲端運算 <a class="header-anchor" href="#什麼是雲端運算" aria-label="Permalink to &quot;什麼是雲端運算&quot;">​</a></h2><p>傳統公司要架設一套系統，得先買伺服器、租機房、請人維護，所有費用在上線前就得付清——還要猜「未來需要多大容量」。猜多了，機器閒置燒錢；猜少了，流量一來就垮掉，再追加也來不及。</p><p>雲端把這個賭注消掉了。<strong>雲端運算是「透過網際網路按需取用 IT 資源、依用量付費」</strong>——就像用電是按度計費，你家不需要自己買發電機。</p><p>雲端最核心的財務優勢，就是把 IT 支出從 <strong>CapEx</strong> 轉變成 <strong>OpEx</strong>：</p><table tabindex="0"><thead><tr><th>名詞</th><th>意思</th><th>例子</th></tr></thead><tbody><tr><td><strong>CapEx</strong>（Capital Expenditure，資本支出）</td><td>先砸一大筆錢購置設備，費用一次性發生</td><td>買伺服器、蓋機房</td></tr><tr><td><strong>OpEx</strong>（Operating Expenditure，營運支出）</td><td>用多少付多少的浮動費用</td><td>按月付 AWS 帳單</td></tr></tbody></table><p>以學校選課系統為例：開學前兩天是選課高峰，幾萬人同時搶課；其餘 90% 的時間幾乎沒有流量。如果學校自建機房（CapEx），得按尖峰容量一次買足夠多的伺服器，但這些機器平常閒著白白燒電費。換成雲端（OpEx），選課期間自動擴大、結束就縮回，費用完全跟著實際用量走。</p><h3 id="三種部署模型" tabindex="-1">三種部署模型 <a class="header-anchor" href="#三種部署模型" aria-label="Permalink to &quot;三種部署模型&quot;">​</a></h3><p>要多少自己建、要多少委外，取決於公司的情況。這就有了三種選擇：</p><table tabindex="0"><thead><tr><th>模型</th><th>說明</th><th>適合</th></tr></thead><tbody><tr><td><strong>雲端（Cloud）</strong></td><td>全部跑在 AWS 等雲端平台</td><td>新創、雲端原生應用</td></tr><tr><td><strong>地端（On-premises）</strong></td><td>全部在自己機房，自行採購與維護實體硬體</td><td>法規嚴格、已有大量本地投資</td></tr><tr><td><strong>混合（Hybrid）</strong></td><td>部分在雲、部分在本地，兩邊連通</td><td>逐步上雲、特定資料須留在本地</td></tr></tbody></table><h3 id="三種服務模型" tabindex="-1">三種服務模型 <a class="header-anchor" href="#三種服務模型" aria-label="Permalink to &quot;三種服務模型&quot;">​</a></h3><p>使用雲端時，「你自己要管多少」可以有不同程度的選擇。愈往 SaaS 走，AWS 幫你管的東西愈多，你能控制的細節也愈少：</p><table tabindex="0"><thead><tr><th>模型</th><th>你管什麼</th><th>AWS 管什麼</th></tr></thead><tbody><tr><td><strong>IaaS</strong>（基礎設施即服務）</td><td>OS 以上全部（自己裝系統、設定環境）</td><td>硬體、網路、虛擬化</td></tr><tr><td><strong>PaaS</strong>（平台即服務）</td><td>只管程式碼與資料</td><td>OS、執行環境</td></tr><tr><td><strong>SaaS</strong>（軟體即服務）</td><td>直接用，幾乎什麼都不管</td><td>幾乎全部</td></tr></tbody></table><p>用吃披薩來記這個光譜：IaaS 是租店家的烤箱自帶食材，PaaS 是買冷凍披薩回家烤（飲料和餐桌自己準備），SaaS 是直接上餐廳——管的事愈來愈少，自由度也愈來愈低。</p><p>延伸閱讀：<a href="https://www.redhat.com/en/topics/cloud-computing/iaas-vs-paas-vs-saas" target="_blank" rel="noreferrer">IaaS vs. PaaS vs. SaaS（Red Hat）</a></p><h2 id="雲端的六大好處" tabindex="-1">雲端的六大好處 <a class="header-anchor" href="#雲端的六大好處" aria-label="Permalink to &quot;雲端的六大好處&quot;">​</a></h2><p>AWS 定義了採用雲端的六大優勢，考試常給情境問「這體現了哪個好處」。先看下表掌握對應關鍵字，再讀各項說明：</p><table tabindex="0"><thead><tr><th>#</th><th>英文</th><th>好處</th><th>情境</th></tr></thead><tbody><tr><td>1</td><td>Trade Fixed Expense for Variable Expense</td><td>不先砸錢買設備，用多少付多少</td><td>「不想先投入大筆資本」</td></tr><tr><td>2</td><td>Benefit from Massive Economies of Scale</td><td>跟 AWS 百萬客戶共享低採購成本</td><td>「降低單位成本」</td></tr><tr><td>3</td><td>Stop Guessing Capacity</td><td>要多少開多少，不用猜</td><td>「不確定流量」「避免猜錯容量」</td></tr><tr><td>4</td><td>Increase Speed and Agility</td><td>幾分鐘部署，不用等採購</td><td>「快速實驗 / 上線」</td></tr><tr><td>5</td><td>Stop Spending on Data Centers</td><td>不必管機房、電力、硬體</td><td>「專注本業，不想管基礎設施」</td></tr><tr><td>6</td><td>Go Global in Minutes</td><td>幾個步驟就能在全球各地上線</td><td>「服務全球使用者 / 降低延遲」</td></tr></tbody></table><h3 id="_1-trade-fixed-expense-for-variable-expense-以變動支出取代固定支出" tabindex="-1">1. Trade Fixed Expense for Variable Expense（以變動支出取代固定支出） <a class="header-anchor" href="#_1-trade-fixed-expense-for-variable-expense-以變動支出取代固定支出" aria-label="Permalink to &quot;1. Trade Fixed Expense for Variable Expense（以變動支出取代固定支出）&quot;">​</a></h3><p>「固定支出」的意思是：不管這筆投資將來划不划算，你都得在<strong>第一天先付清一大筆錢</strong>。對一個還沒有任何使用者、還不知道會不會成功的新產品來說，這是一場豪賭——押對了，當初買的機器剛好夠用；押錯了，要嘛買太多、機器整年閒著折舊，要嘛買太少、真的紅了卻擴充不及。</p><p>雲端把這場豪賭換成「變動支出」：費用跟著<strong>實際用量</strong>走。一個乏人問津的專案幾乎不花錢，一個成長中的專案則隨規模按比例付費——你永遠不會在拿到價值之前先付錢。這也大幅拉低了「試新東西」的門檻：想驗證一個點子，成本從一張伺服器採購單，變成幾個小時的運算費用。</p><h3 id="_2-benefit-from-massive-economies-of-scale-享受規模經濟" tabindex="-1">2. Benefit from Massive Economies of Scale（享受規模經濟） <a class="header-anchor" href="#_2-benefit-from-massive-economies-of-scale-享受規模經濟" aria-label="Permalink to &quot;2. Benefit from Massive Economies of Scale（享受規模經濟）&quot;">​</a></h3><p>規模經濟的運作原理：當數十萬個客戶的用量被集中到同一個平台，AWS 採購硬體、電力與網路的規模，是任何單一公司都達不到的，於是每單位成本被壓到極低；又因為這是一個按用量計價、彼此競爭的市場，這些省下來的成本會透過<strong>更低的價格</strong>回饋給每個客戶。</p><p>可以想成量販店：一次替幾百萬人採買，拿到的單價是一個家庭自己去買永遠談不到的。</p><h3 id="_3-stop-guessing-capacity-免除預估容量" tabindex="-1">3. Stop Guessing Capacity（免除預估容量） <a class="header-anchor" href="#_3-stop-guessing-capacity-免除預估容量" aria-label="Permalink to &quot;3. Stop Guessing Capacity（免除預估容量）&quot;">​</a></h3><p>自建機房困難的地方在於：必須在<strong>資訊最少的時候</strong>（上線前）就決定要買多少容量。猜的結果只有兩種壞法——猜多了，一整排伺服器閒著燒電費與折舊；猜少了，流量一來就垮，而追加實體伺服器要等好幾週，根本來不及救。</p><p>雲端直接把「猜」這個動作拿掉：現在需要多少就開多少，再搭配 <strong>Auto Scaling</strong> 讓資源隨實際需求自動增減。回到前面的選課系統——選課那兩天自動放大、結束就縮回，全程不需要事先預測尖峰有多高。這種「隨需求彈性伸縮」的能力，是雲端最具代表性的優勢。</p><h3 id="_4-increase-speed-and-agility-提升速度與敏捷性" tabindex="-1">4. Increase Speed and Agility（提升速度與敏捷性） <a class="header-anchor" href="#_4-increase-speed-and-agility-提升速度與敏捷性" aria-label="Permalink to &quot;4. Increase Speed and Agility（提升速度與敏捷性）&quot;">​</a></h3><p>過去要拿到一台伺服器，得走採購流程、下訂、等貨、上架安裝，前後往往數週到數月。這條長長的前置時間有個隱藏代價：因為「開一台機器」又慢又貴，團隊會傾向<strong>不敢輕易嘗試</strong>有風險的新點子。</p><p>在 AWS 上佈建環境只要幾分鐘，而且開得起、也拆得起。當「試一次」的成本趨近於零，團隊的行為就變了：可以放手實驗、便宜地失敗、快速迭代。敏捷性的重點不只是「快」，更是這種低實驗成本帶來的<strong>放膽去試的自由</strong>。</p><h3 id="_5-stop-spending-money-on-running-and-maintaining-data-centers-省下維運機房的費用" tabindex="-1">5. Stop Spending Money on Running and Maintaining Data Centers（省下維運機房的費用） <a class="header-anchor" href="#_5-stop-spending-money-on-running-and-maintaining-data-centers-省下維運機房的費用" aria-label="Permalink to &quot;5. Stop Spending Money on Running and Maintaining Data Centers（省下維運機房的費用）&quot;">​</a></h3><p>自己經營一座資料中心，是一筆和你真正的產品<strong>毫無關係</strong>的持續開銷：供電、散熱、實體門禁、定期更換故障硬體，還要專人負責上架伺服器、半夜換掉壞掉的硬碟。這類工作 AWS 稱為「undifferentiated heavy lifting（無差異化的粗重工作）」——做得再好也不會讓你的產品更有競爭力。</p><p>把這些全部交給 AWS，你的工程人力就能專注在真正能做出差異的地方——你的應用本身。對一間新創來說，差別就是工程師在寫功能，而不是去機房換硬碟。</p><h3 id="_6-go-global-in-minutes-數分鐘內全球佈署" tabindex="-1">6. Go Global in Minutes（數分鐘內全球佈署） <a class="header-anchor" href="#_6-go-global-in-minutes-數分鐘內全球佈署" aria-label="Permalink to &quot;6. Go Global in Minutes（數分鐘內全球佈署）&quot;">​</a></h3><p>用傳統做法要服務另一個大洲的使用者，你得在當地找地、租機房、把設備一路建起來——好幾個月的工程與龐大成本，以致多數公司根本做不到。</p><p>有了 AWS 遍布全球的 Region，把服務擴展到新的地理區只需要幾個步驟，使用者就能連到離自己最近的基礎設施，延遲更低、體驗更穩。這等於把「拓展到全球」從一項大型資本工程，變成了一個<strong>設定選項</strong>。舉例來說，一個台灣的應用想服務美國使用者，只要多開一個美國 Region，美國那端就不必再繞過整個太平洋來連線。</p><h2 id="aws-全球基礎設施" tabindex="-1">AWS 全球基礎設施 <a class="header-anchor" href="#aws-全球基礎設施" aria-label="Permalink to &quot;AWS 全球基礎設施&quot;">​</a></h2><p>AWS 把實體設施分成三個層級，設計這些層級的原因不只是地理方便，更是為了隔離故障：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Region（區域，如 ap-northeast-1 東京）</span></span>
<span class="line"><span>  └─ Availability Zone（可用區，一個 Region 通常 ≥ 3 個）</span></span>
<span class="line"><span>       └─ 一或多個實體資料中心</span></span>
<span class="line"><span>（另外散布全球的）Edge Location（邊緣節點）→ 給 CloudFront 做快取</span></span></code></pre></div><table tabindex="0"><thead><tr><th>層級</th><th>是什麼</th><th>重點</th></tr></thead><tbody><tr><td><strong>Region（區域）</strong></td><td>全球各地的地理區域</td><td>彼此<strong>獨立隔離</strong>；資料預設不自動跨 Region 移動</td></tr><tr><td><strong>Availability Zone（可用區）</strong></td><td>Region 內獨立的資料中心群</td><td>實體隔離（不同電力 / 機房），但以低延遲高速網路相連</td></tr><tr><td><strong>Edge Location（邊緣節點）</strong></td><td>散布全球的快取點，數量遠多於 Region</td><td>CloudFront 用它把內容放到離使用者最近的地方</td></tr></tbody></table><p>為什麼一個 Region 要拆成多個實體隔離的 Availability Zone？因為這樣一個機房失火或斷電，另一個 Availability Zone 還活著——把應用程式跨多個 Availability Zone 部署，就是高可用架構的基礎。</p><blockquote><p>📌 <strong>全域服務 vs 區域服務</strong>：EC2、S3、RDS 等絕大多數服務都是 <strong>Region 範圍</strong>，建立資源時要選 Region。但有少數服務是<strong>全域</strong>的，不需選 Region——<strong>IAM</strong>（帳號權限）、<strong>Route 53</strong>（DNS）、<strong>CloudFront</strong>（CDN）、<strong>帳單（Billing）</strong> 設定在所有 Region 共用。</p></blockquote><h3 id="如何選擇-region" tabindex="-1">如何選擇 Region <a class="header-anchor" href="#如何選擇-region" aria-label="Permalink to &quot;如何選擇 Region&quot;">​</a></h3><p>選 Region 要綜合四個因素考量：</p><ol><li><strong>法規與資料落地（Compliance）</strong> — 法規要求資料留在特定國家 → 選該國 Region，此項優先於其他考量</li><li><strong>貼近使用者（Proximity）</strong> — 使用者在哪，就選近的 Region 降低延遲</li><li><strong>服務可用性（Feature availability）</strong> — 新服務不是每個 Region 都有，要先確認</li><li><strong>價格（Pricing）</strong> — 不同 Region 定價不同</li></ol><h2 id="責任共擔模型-shared-responsibility-model" tabindex="-1">責任共擔模型（Shared Responsibility Model） <a class="header-anchor" href="#責任共擔模型-shared-responsibility-model" aria-label="Permalink to &quot;責任共擔模型（Shared Responsibility Model）&quot;">​</a></h2><p>使用 AWS 不代表安全都交給 AWS 處理，AWS 和你是分工關係：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>AWS  負責「雲本身的安全」（Security OF the Cloud）</span></span>
<span class="line"><span>你   負責「雲裡面的安全」（Security IN the Cloud）</span></span></code></pre></div><table tabindex="0"><thead><tr><th>誰負責</th><th>範圍</th></tr></thead><tbody><tr><td>AWS</td><td>實體資料中心、硬體、底層網路、虛擬化層</td></tr><tr><td>你</td><td>資料、IAM 權限設定、OS 與防火牆（EC2）、加密設定、應用程式</td></tr></tbody></table><p>責任界線隨服務類型移動——服務愈託管，AWS 扛的愈多。以「系統更新」為例：</p><ul><li>EC2（IaaS）：你有 root 權限，OS 是你的地盤，更新得自己來</li><li>RDS（託管服務）：資料庫引擎的更新由 AWS 負責，你只管資料與存取權限</li></ul><blockquote><p>📌 無論用哪種服務，<strong>資料</strong>與 <strong>IAM 權限設定</strong>永遠是客戶的責任。</p></blockquote><h2 id="重點整理" tabindex="-1">重點整理 <a class="header-anchor" href="#重點整理" aria-label="Permalink to &quot;重點整理&quot;">​</a></h2><ul><li><strong>雲端運算</strong> = 透過網路按需取用 IT 資源、依用量付費</li><li>部署模型：雲端 / 地端 / 混合</li><li>服務模型：<strong>IaaS</strong>（自管 OS，如 EC2）、<strong>PaaS</strong>（只管程式碼，如 Beanstalk）、<strong>SaaS</strong>（直接用，如 Gmail）；愈往 SaaS 走 AWS 扛愈多</li><li>六大好處能對應情境關鍵字；最重要：<strong>不必再預估容量</strong>（對應 Auto Scaling）</li><li>全球基礎設施三層：<strong>Region</strong>（獨立地理區域）&gt; <strong>AZ</strong>（實體隔離但低延遲相連的機房群）&gt; <strong>Edge Location</strong>（CloudFront 快取點，數量最多）</li><li>跨多個 <strong>AZ</strong> 部署 = 高可用的基礎（一個 AZ 掛了還有別的）</li><li>選 Region 四考量：<strong>法規落地 &gt; 貼近使用者 &gt; 服務可用性 &gt; 價格</strong></li><li><strong>全域服務</strong>：<strong>IAM、Route 53、CloudFront、帳單</strong>；其他絕大多數服務都是 Region 範圍</li><li><strong>責任共擔</strong>：AWS 管「雲本身（OF）」，客戶管「雲裡面（IN）」；OS 補丁：EC2 是客戶責任、RDS 是 AWS 責任</li><li>資料與 IAM 權限設定永遠是客戶責任，與服務類型無關</li></ul>`,55)])])}const b=a(r,[["render",i]]);export{c as __pageData,b as default};
